import{_ as e,o as a,c as t,a2 as i}from"./chunks/framework.IwO0Hdn_.js";const g=JSON.parse('{"title":"[UI / PRESENTATION] F-04.3 — Filtros en el Histórico","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-04.3_filtros_historico.md","filePath":"backlog/F-04.3_filtros_historico.md","lastUpdated":null}'),r={name:"backlog/F-04.3_filtros_historico.md"};function s(c,o,n,l,d,p){return a(),t("div",null,[...o[0]||(o[0]=[i('<h1 id="ui-presentation-f-04-3-—-filtros-en-el-historico" tabindex="-1">[UI / PRESENTATION] F-04.3 — Filtros en el Histórico <a class="header-anchor" href="#ui-presentation-f-04-3-—-filtros-en-el-historico" aria-label="Permalink to &quot;[UI / PRESENTATION] F-04.3 — Filtros en el Histórico&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-04 — Histórico de Logs Archivados</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>UI / Presentation</code><strong>Impacta en:</strong> Equipo Frontend (Livewire/Blade)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-04.1_vista_historico_pestana.html">F-04.1</a></td><td>Componente Livewire <code>ArchivedLogsTable</code> base implementado</td></tr><tr><td><a href="./F-02.2_filtro_tipo_error.html">F-02.2</a></td><td>Patrón de filtro por tipo ya probado en <code>LogsTable</code> (se reutiliza el patrón, no el componente)</td></tr><tr><td><a href="./F-02.3_filtro_aplicacion.html">F-02.3</a></td><td>Patrón de filtro por aplicación ya probado</td></tr><tr><td><a href="./F-02.4_filtro_fechas.html">F-02.4</a></td><td>Patrón de filtro por fechas ya probado</td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Must</code></p><hr><p><strong>Descripción:</strong> Como administrador del sistema Quiero que la vista de histórico disponga de los mismos filtros que la vista de logs activos Para localizar registros archivados específicos con la misma facilidad</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Filtro por tipo):</strong> Dado que estoy en el histórico y selecciono el filtro &quot;Critical&quot;, cuando se aplica, entonces solo se muestran logs archivados de tipo Critical.</li><li>[ ] <strong>Escenario 2 (Filtro por aplicación):</strong> Dado que selecciono una aplicación en el filtro, cuando se aplica, entonces solo aparecen los archivados de esa aplicación.</li><li>[ ] <strong>Escenario 3 (Filtro por fecha):</strong> Dado que introduzco un rango de fechas, cuando se aplica el filtro, entonces filtra por <code>archived_at</code> (fecha de archivado, no de creación del log original).</li><li>[ ] <strong>Escenario 4 (Combinación):</strong> Dado que aplico varios filtros simultáneamente, cuando se cargan los resultados, entonces se cumplen todas las condiciones a la vez.</li><li>[ ] <strong>Requisito Técnico:</strong> Los filtros del histórico operan sobre la tabla <code>archived_logs</code>. El filtro de fecha usa el campo <code>archived_at</code>. Reutilizar el mismo patrón de propiedades Livewire con <code>#[Url]</code> del componente <code>ArchivedLogsTable</code>.</li></ul>',12)])])}const f=e(r,[["render",s]]);export{g as __pageData,f as default};
